import random
from itertools import combinations

N=70

def find_draw(tickets):
    # backtracking choose 6 nums satisfying <=1 overlap per ticket
    tsets=[set(t) for t in tickets]
    nums=list(range(1,N+1))
    # heuristic order by frequency high first maybe
    freq={x:0 for x in nums}
    for t in tsets:
        for x in t: freq[x]+=1
    nums.sort(key=lambda x:freq[x])
    chosen=[]
    cnt=[0]*len(tsets)

    def dfs(idx,start):
        if idx==6: return chosen.copy()
        # pruning remaining numbers
        for i in range(start,len(nums)):
            x=nums[i]
            bad=False
            touched=[]
            for j,t in enumerate(tsets):
                if x in t:
                    if cnt[j]>=1:
                        bad=True; break
                    touched.append(j)
            if bad: continue
            chosen.append(x)
            for j in touched: cnt[j]+=1
            r=dfs(idx+1,i+1)
            if r: return r
            for j in touched: cnt[j]-=1
            chosen.pop()
        return None
    return dfs(0,0)


def random_tickets(m=40):
    return [random.sample(range(1,N+1),6) for _ in range(m)]

for it in range(200):
    T=random_tickets(40)
    d=find_draw(T)
    if d is None:
        print('no draw found at iter',it)
        break
else:
    print('all had draw')

