#!/usr/bin/env python3
from pwn import remote, context
import re, time, statistics
from collections import Counter

context.log_level='error'
HOST='crypto.chal.csaw.io'; PORT=5000
DRAW_RE=re.compile(rb"Draw\s+(\d+):\s+\{([^}]*)\}, profit: \$(-?\d+)")

def recv_until_prompt(r, timeout=6):
    return r.recvuntil(b'>> ', timeout=timeout)

def safe_close(r):
    try:r.close()
    except:pass

def play_one(ticket=(1,2,3,4,5,6)):
    r=None
    try:
        r=remote(HOST,PORT,timeout=6)
        recv_until_prompt(r)
        r.sendline(b'1')
        for n in ticket:
            recv_until_prompt(r)
            r.sendline(str(n).encode())
        data=b''
        end=time.time()+8
        while time.time()<end:
            try:
                c=r.recv(timeout=0.5)
                if not c: break
                data+=c
                if b'Ah shucks' in data: break
            except EOFError:
                break
        m=DRAW_RE.search(data)
        if not m: return None
        draw=tuple(sorted(int(x.strip()) for x in m.group(2).split(b',') if x.strip()))
        return (int(m.group(1)), draw, int(m.group(3)))
    except Exception:
        return None
    finally:
        if r: safe_close(r)

def start_paused(partial=5):
    r=remote(HOST,PORT,timeout=6)
    recv_until_prompt(r); r.sendline(b'1')
    for i in range(1,partial+1):
        recv_until_prompt(r); r.sendline(str(i).encode())
    return r

def resume_get(r, final=6):
    try:
        recv_until_prompt(r, timeout=6)
        r.sendline(str(final).encode())
        data=b''
        end=time.time()+8
        while time.time()<end:
            try:
